+export function getVote(input: {
+  reviewId: string;
+  visitorId: string;
+}): ReviewVote | null {
+  const store = getStore();
+  const voteKey = makeVoteKey(input.reviewId, input.visitorId);
+  return store.votes.get(voteKey) ?? null;
+}
