+export function reportReview(input: {
+  reviewId: string;
+  reporterId: string;
+  reason?: string;
+}): boolean {
+  const store = getStore();
+  const review = store.reviews.get(input.reviewId);
+
+  if (!review) {
+    return false;
+  }
+
+  review.reported = true;
+  review.updatedAt = new Date().toISOString();
+  store.reviews.set(input.reviewId, review);
+
+  return true;
+}
